#
# Returns a string.
# ============================================================
function Format-RotationReport {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [hashtable]$Report,

        [Parameter(Mandatory)]
        [ValidateSet('JSON', 'Markdown')]
        [string]$Format
    )

    switch ($Format) {
        'JSON' {
            return _Format-Json -Report $Report
        }
        'Markdown' {
