    21→        # Fixed reference date for deterministic tests
    22→        $script:ReferenceDate = [datetime]'2024-01-15'
    23→    }
    24→
    25→    Context 'Expired secrets' {
    26→        It 'classifies a secret as Expired when past its rotation deadline' {
    27→            # A secret rotated 100 days ago with a 90-day policy is expired
    28→            $secret = @{
    29→                Name              = 'DB_PASSWORD'
    30→                LastRotated       = '2023-10-07'  # 100 days before 2024-01-15
    31→                RotationPolicyDays = 90
    32→                RequiredBy        = @('api-service', 'worker')
    33→            }
    34→
    35→            $result = Get-SecretStatus -Secret $secret -ReferenceDate $script:ReferenceDate -WarningWindowDays 14
    36→
    37→            $result.Status | Should -Be 'Expired'
    38→        }
    39→
    40→        It 'classifies a secret as Expired exactly on its expiry date' {
    41→            # Rotated exactly 90 days ago with a 90-day policy
    42→            $secret = @{
    43→                Name              = 'API_KEY'
    44→                LastRotated       = '2023-10-17'  # 90 days before 2024-01-15
    45→                RotationPolicyDays = 90
    46→                RequiredBy        = @('frontend')
    47→            }
    48→
    49→            $result = Get-SecretStatus -Secret $secret -ReferenceDate $script:ReferenceDate -WarningWindowDays 14
    50→
    51→            $result.Status | Should -Be 'Expired'
    52→        }
    53→    }
    54→
    55→    Context 'Warning secrets' {
    56→        It 'classifies a secret as Warning when expiring within the warning window' {
    57→            # Rotated 80 days ago with a 90-day policy: expires in 10 days (within 14-day window)
    58→            $secret = @{
    59→                Name              = 'OAUTH_SECRET'
    60→                LastRotated       = '2023-10-27'  # 80 days before 2024-01-15
    61→                RotationPolicyDays = 90
    62→                RequiredBy        = @('auth-service')
    63→            }
    64→
    65→            $result = Get-SecretStatus -Secret $secret -ReferenceDate $script:ReferenceDate -WarningWindowDays 14
    66→
    67→            $result.Status | Should -Be 'Warning'
    68→        }
    69→
    70→        It 'classifies a secret as Warning exactly at the warning window boundary' {
    71→            # Rotated 76 days ago with a 90-day policy: expires in 14 days (boundary)
    72→            $secret = @{
    73→                Name              = 'SMTP_PASSWORD'
    74→                LastRotated       = '2023-10-31'  # 76 days before 2024-01-15
    75→                RotationPolicyDays = 90
    76→                RequiredBy        = @('notification-service')
    77→            }
    78→
    79→            $result = Get-SecretStatus -Secret $secret -ReferenceDate $script:ReferenceDate -WarningWindowDays 14
    80→
    81→            $result.Status | Should -Be 'Warning'
    82→        }
    83→    }
    84→
    85→    Context 'OK secrets' {
