    87→            # Rotated 10 days ago with a 90-day policy: 80 days remaining
    88→            $secret = @{
    89→                Name              = 'JWT_SECRET'
    90→                LastRotated       = '2024-01-05'  # 10 days before 2024-01-15
    91→                RotationPolicyDays = 90
    92→                RequiredBy        = @('api-service')
    93→            }
    94→
    95→            $result = Get-SecretStatus -Secret $secret -ReferenceDate $script:ReferenceDate -WarningWindowDays 14
    96→
    97→            $result.Status | Should -Be 'Ok'
    98→        }
    99→
   100→        It 'classifies a secret as Ok when just outside the warning window' {
